// Read and parse trade journal
const fs = require('fs');
const journalPath = $json.journal_path;

let allTrades = [];
if (fs.existsSync(journalPath)) {
  try {
    allTrades = JSON.parse(fs.readFileSync(journalPath, 'utf8'));
  } catch (e) {
    console.error('Error reading journal:', e);
  }
}

const weekStart = new Date($json.week_start);
const weekEnd = new Date(Date.now());

// Filter trades from this week that are closed
const weekTrades = allTrades.filter(trade => {
  const tradeTime = new Date(trade.signal_time);
  return tradeTime >= weekStart && tradeTime <= weekEnd && trade.status === 'closed' && trade.pnl !== null;
});

// Calculate metrics
let totalPnL = 0;
let winCount = 0;
let lossCount = 0;
let totalWins = 0;
let totalLosses = 0;
let maxDrawdown = 0;
let pairStats = {};
let equity = 10000; // Starting equity
let equityCurve = [10000];

weekTrades.forEach(trade => {
  const pnl = parseFloat(trade.pnl);
  totalPnL += pnl;
  equity += pnl;
  equityCurve.push(equity);

  if (pnl > 0) {
    winCount++;
    totalWins += pnl;
  } else {
    lossCount++;
    totalLosses += Math.abs(pnl);
  }

  // Track max drawdown
  const peak = Math.max(...equityCurve);
  const drawdown = ((equity - peak) / peak) * 100;
  if (drawdown < maxDrawdown) maxDrawdown = drawdown;

  // Track per-pair stats
  if (!pairStats[trade.ticker]) {
    pairStats[trade.ticker] = { trades: 0, pnl: 0, wins: 0, losses: 0 };
  }
  pairStats[trade.ticker].trades++;
  pairStats[trade.ticker].pnl += pnl;
  if (pnl > 0) pairStats[trade.ticker].wins++;
  else pairStats[trade.ticker].losses++;
});

const totalTrades = winCount + lossCount;
const winRate = totalTrades > 0 ? (winCount / totalTrades * 100).toFixed(2) : 0;
const avgWin = winCount > 0 ? (totalWins / winCount).toFixed(2) : 0;
const avgLoss = lossCount > 0 ? (totalLosses / lossCount).toFixed(2) : 0;
const profitFactor = totalLosses > 0 ? (totalWins / totalLosses).toFixed(2) : (totalWins > 0 ? 'Inf' : 0);

// Calculate Sharpe ratio (simplified)
const returns = equityCurve.slice(1).map((e, i) => (e - equityCurve[i]) / equityCurve[i]);
const avgReturn = returns.length > 0 ? returns.reduce((a, b) => a + b) / returns.length : 0;
const stdDev = returns.length > 0 ? Math.sqrt(returns.reduce((sq, n) => sq + Math.pow(n - avgReturn, 2)) / returns.length) : 0;
const sharpeRatio = stdDev > 0 ? (avgReturn / stdDev * Math.sqrt(252 / 5)).toFixed(2) : 0; // 252 trading days, 5-day week

return {
  report_period: `${$json.week_start} to ${$json.report_date}`,
  total_trades: totalTrades,
  total_pnl: totalPnL.toFixed(2),
  win_rate: winRate,
  wins: winCount,
  losses: lossCount,
  avg_win: avgWin,
  avg_loss: avgLoss,
  profit_factor: profitFactor,
  max_drawdown: maxDrawdown.toFixed(2),
  sharpe_ratio: sharpeRatio,
  final_equity: equity.toFixed(2),
  pair_stats: pairStats,
  trades: weekTrades
};

// Find best and worst performers
const pairs = $json.pair_stats;
let bestPair = { name: 'N/A', pnl: -Infinity, trades: 0 };
let worstPair = { name: 'N/A', pnl: Infinity, trades: 0 };

Object.entries(pairs).forEach(([pair, stats]) => {
  if (stats.pnl > bestPair.pnl) {
    bestPair = { name: pair, pnl: stats.pnl.toFixed(2), trades: stats.trades, wr: (stats.wins/stats.trades*100).toFixed(1) };
  }
  if (stats.pnl < worstPair.pnl) {
    worstPair = { name: pair, pnl: stats.pnl.toFixed(2), trades: stats.trades, wr: (stats.wins/stats.trades*100).toFixed(1) };
  }
});

return {
  ...($json),
  best_pair: bestPair,
  worst_pair: worstPair
};

