// Save detailed report to file
const fs = require('fs');
const path = require('path');

const reportDir = '/sessions/busy-awesome-noether/mnt/forex_scalper_bot/weekly_reports';
if (!fs.existsSync(reportDir)) {
  fs.mkdirSync(reportDir, { recursive: true });
}

const filename = path.join(reportDir, `weekly_report_${new Date().getTime()}.json`);

const report = {
  report_date: new Date().toISOString(),
  period: $json.report_period,
  summary: {
    total_trades: $json.total_trades,
    total_pnl: parseFloat($json.total_pnl),
    win_rate: parseFloat($json.win_rate),
    wins: $json.wins,
    losses: $json.losses,
    avg_win: parseFloat($json.avg_win),
    avg_loss: parseFloat($json.avg_loss),
    profit_factor: $json.profit_factor,
    max_drawdown: parseFloat($json.max_drawdown),
    sharpe_ratio: parseFloat($json.sharpe_ratio),
    final_equity: parseFloat($json.final_equity)
  },
  pair_performance: $json.pair_stats,
  best_pair: $json.best_pair,
  worst_pair: $json.worst_pair,
  ai_analysis: $json.output,
  trades: $json.trades
};

fs.writeFileSync(filename, JSON.stringify(report, null, 2));
return { saved_to: filename, status: 'success' };

// Export summary CSV for record-keeping
const fs = require('fs');
const path = require('path');

const csvDir = '/sessions/busy-awesome-noether/mnt/forex_scalper_bot/reports_csv';
if (!fs.existsSync(csvDir)) {
  fs.mkdirSync(csvDir, { recursive: true });
}

const headers = 'Date,Period,TotalTrades,WinRate,TotalPnL,Wins,Losses,AvgWin,AvgLoss,ProfitFactor,MaxDrawdown,SharpeRatio,FinalEquity,BestPair,WorstPair';
const row = `${new Date().toISOString()},${$json.report_period},${$json.total_trades},${$json.win_rate}%,${$json.total_pnl},${$json.wins},${$json.losses},${$json.avg_win},${$json.avg_loss},${$json.profit_factor},${$json.max_drawdown}%,${$json.sharpe_ratio},${$json.final_equity},${$json.best_pair.name},${$json.worst_pair.name}`;

const csvPath = path.join(csvDir, 'weekly_summary.csv');
let content = '';
if (!fs.existsSync(csvPath)) {
  content = headers + '\n';
}
else {
  content = fs.readFileSync(csvPath, 'utf8');
}

content += row + '\n';
fs.writeFileSync(csvPath, content);

return { csv_saved: csvPath, status: 'success' };
